// ── JORDAN SEND EMAIL v1.0 ──────────────────────────────
// Node 1: Validate inputs + dedup guard via Supabase check
const https = require('https');
const input = $input.first().json;

const to          = (input.to || '').trim();
const bcc         = (input.bcc || 'kas42869@gmail.com').trim();
const subject     = (input.subject || 'KAI-Netics Outreach').trim();
const body        = (input.body || '').trim();
const pipelineId  = input.pipelineId || null;
const entity      = input.entity || 'FP';
const source      = input.source || 'dashboard';

if (!to)   throw new Error('No recipient email address provided');
if (!body) throw new Error('No email body provided');

// Dedup guard — check if loi_sent already true on pipeline record
if (pipelineId) {
  const SUPABASE_URL = ($env.SUPABASE_URL || '').replace('https://','').replace('http://','');
  const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY || '';
  const check = await new Promise((resolve, reject) => {
    const req = https.request({
      hostname: SUPABASE_URL, port: 443,
      path: '/rest/v1/pipeline?id=eq.' + pipelineId + '&select=loi_sent,title',
      method: 'GET',
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY }
    }, (res) => { let d=''; res.on('data',c=>d+=c); res.on('end',()=>resolve({status:res.statusCode,body:d})); });
    req.on('error', reject);
    req.end();
  });
  try {
    const rows = JSON.parse(check.body);
    if (Array.isArray(rows) && rows.length > 0 && rows[0].loi_sent === true) {
      throw new Error('DEDUP_BLOCK: LOI already sent for this opportunity (' + (rows[0].title||pipelineId) + '). Update pipeline record manually if resend is intentional.');
    }
  } catch(e) {
    if (e.message.startsWith('DEDUP_BLOCK')) throw e;
    // Parse error — proceed
  }
}

return [{ json: { to, bcc, subject, body, pipelineId, entity, source, sentAt: new Date().toISOString() } }];

// ── Node 2: Format body + build HTML ───────────────────
// Strips markdown, builds entity-aware HTML signature
const input = $input.first().json;
const entity = input.entity || 'FP';

// ── Clean markdown from plain text body ──
function cleanMarkdown(text) {
  return text
    .replace(/^#{1,6}\s+/gm, '')           // Remove ## headers
    .replace(/\*\*(.+?)\*\*/g, '$1')        // Remove **bold**
    .replace(/\*(.+?)\*/g, '$1')            // Remove *italic*
    .replace(/^[-*]\s+/gm, '\u2022 ')      // Convert list items to bullets
    .replace(/^\|.+\|$/gm, '')             // Remove markdown tables
    .replace(/^[-|\s]+$/gm, '')            // Remove table separators
    .replace(/\[(.+?)\]\((.+?)\)/g, '$1 ($2)') // Flatten links
    .replace(/`(.+?)`/g, '$1')             // Remove inline code
    .replace(/---+/g, '\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500') // Replace HR
    .replace(/\n{3,}/g, '\n\n')            // Collapse excess blank lines
    .trim();
}

// ── Entity-aware signature ──
const signatures = {
  FP: {
    name: 'Kevin Alexander Smith',
    title: 'Founder & Principal',
    company: 'Kevin Alexander International LLC dba KAI-Netics',
    credentials: 'FAA Part 107 #5250157 | CISSP | PMP | CCNA | Security+',
    email: 'kas@kevin-llc.com',
    phone: '443.257.6836',
    web: 'www.kai-netics.com',
    color: '#00e5ff'
  },
  EAF: {
    name: 'Kevin Alexander Smith',
    title: 'Executive Director',
    company: 'KAI-Netics Equity & Autonomy Foundry, Inc.',
    credentials: 'EIN: 41-4820296 | 501(c)(3) Pending | CAKO Program',
    email: 'kas@kevin-llc.com',
    phone: '443.257.6836',
    web: 'www.kai-netics.com',
    color: '#7c6af7'
  },
  MONK: {
    name: 'Kevin Alexander Smith',
    title: 'Founder',
    company: 'MONK LLC / KAI-Netics',
    credentials: 'FAA Part 107 #5250157 | CISSP | PMP',
    email: 'kas@kevin-llc.com',
    phone: '443.257.6836',
    web: 'www.kai-netics.com',
    color: '#ff9f43'
  }
};
const sig = signatures[entity] || signatures.FP;

const cleanBody = cleanMarkdown(input.body);

// ── Plain text version ──
const plainText = cleanBody + '\n\n' +
  sig.name + '\n' +
  sig.title + '\n' +
  sig.company + '\n' +
  sig.credentials + '\n' +
  sig.email + ' | ' + sig.phone + '\n' +
  sig.web;

// ── HTML version ──
const safeBody = cleanBody
  .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
  .replace(/\n\n/g, '</p><p style="margin:0 0 14px 0;">')
  .replace(/\n/g, '<br>');

const htmlBody =
  '<div style="font-family:Arial,sans-serif;max-width:680px;margin:0 auto;">' +
  '<div style="background:#0a1628;padding:18px 24px;border-radius:8px 8px 0 0;">' +
  '<h2 style="color:' + sig.color + ';margin:0;font-size:17px;font-weight:700;">KAI-Netics</h2>' +
  '<p style="color:#8899aa;margin:3px 0 0;font-size:11px;">' + sig.company + '</p>' +
  '</div>' +
  '<div style="background:#ffffff;padding:28px 28px 20px;border:1px solid #e0e0e0;">' +
  '<p style="margin:0 0 14px 0;font-size:14px;line-height:1.8;color:#222;">' + safeBody + '</p>' +
  '</div>' +
  '<div style="background:#f8f9fa;border:1px solid #e0e0e0;border-top:none;padding:16px 24px;border-radius:0 0 8px 8px;">' +
  '<p style="margin:0;font-size:13px;font-weight:700;color:#222;">' + sig.name + '</p>' +
  '<p style="margin:2px 0 0;font-size:12px;color:#555;">' + sig.title + ' | ' + sig.company + '</p>' +
  '<p style="margin:4px 0 0;font-size:11px;color:#777;">' + sig.credentials + '</p>' +
  '<p style="margin:4px 0 0;font-size:11px;color:#777;">' +
  '<a href="mailto:' + sig.email + '" style="color:#0066cc;text-decoration:none;">' + sig.email + '</a>' +
  ' | ' + sig.phone + ' | <a href="http://' + sig.web + '" style="color:#0066cc;text-decoration:none;">' + sig.web + '</a>' +
  '</p>' +
  '</div>' +
  '</div>';

return [{ json: Object.assign({}, input, { cleanBody, plainText, htmlBody, sig }) }];

// ── Node 4: Supabase pipeline update + disk log + WhatsApp ──
const https = require('https');
const http  = require('http');
const fs    = require('fs');
const input = $input.first().json;

const SUPABASE_URL = ($env.SUPABASE_URL || '').replace('https://','').replace('http://','');
const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY || '';

// ── 1. Update pipeline record ──
let supabaseStatus = 'skipped';
if (input.pipelineId && SUPABASE_URL && SUPABASE_KEY) {
  try {
    const patch = JSON.stringify({
      loi_sent:           true,
      loi_sent_date:      input.sentAt,
      loi_recipient:      input.to,
      last_contact_date:  input.sentAt.slice(0,10),
      last_contact_notes: 'Outreach email sent to ' + input.to + ' — ' + input.subject,
      status:             'pursuing',
      last_activity_at:   input.sentAt
    });
    const result = await new Promise((resolve, reject) => {
      const req = https.request({
        hostname: SUPABASE_URL, port: 443,
        path: '/rest/v1/pipeline?id=eq.' + input.pipelineId,
        method: 'PATCH',
        headers: {
          'Content-Type': 'application/json',
          'apikey': SUPABASE_KEY,
          'Authorization': 'Bearer ' + SUPABASE_KEY,
          'Prefer': 'return=minimal',
          'Content-Length': Buffer.byteLength(patch)
        }
      }, (res) => { let d=''; res.on('data',c=>d+=c); res.on('end',()=>resolve({status:res.statusCode,body:d})); });
      req.on('error', reject);
      req.write(patch);
      req.end();
    });
    supabaseStatus = result.status === 204 || result.status === 200 ? 'updated' : 'error_' + result.status;
  } catch(e) {
    supabaseStatus = 'error: ' + e.message;
  }
}

// ── 2. Log sent email to disk ──
const sentDir = '/data/Aidan_Outputs/Jordan/Sent';
fs.mkdirSync(sentDir, { recursive: true });
const safeName = (input.subject || 'email').replace(/[^a-zA-Z0-9]/g, '_').substring(0, 50);
const logPath = sentDir + '/SENT_' + input.sentAt.replace(/[:.]/g,'-') + '_' + safeName + '.txt';
const logContent = [
  'JORDAN SENT EMAIL LOG',
  'Sent:        ' + input.sentAt,
  'To:          ' + input.to,
  'BCC:         ' + input.bcc,
  'Subject:     ' + input.subject,
  'Entity:      ' + (input.entity || 'FP'),
  'Pipeline ID: ' + (input.pipelineId || 'N/A'),
  'Supabase:    ' + supabaseStatus,
  'Source:      ' + input.source,
  '',
  '─── BODY ───────────────────────────────────────',
  input.cleanBody || input.body
].join('\n');
try { fs.writeFileSync(logPath, logContent, 'utf8'); } catch(e) {}

// ── 3. WhatsApp confirmation ──
const msg = [
  'JORDAN EMAIL SENT',
  '',
  'To: ' + input.to,
  'Subject: ' + input.subject,
  'BCC: ' + input.bcc,
  'Pipeline: ' + (input.pipelineId || 'N/A'),
  'Supabase: ' + supabaseStatus,
  'Log: ' + logPath
].join('\n');
const msgBody = JSON.stringify({ number: '14432576836@s.whatsapp.net', textMessage: { text: msg } });
const opts = {
  hostname: 'host.docker.internal', port: 8081,
  path: '/message/sendText/Aidan', method: 'POST',
  headers: { 'Content-Type': 'application/json', 'apikey': 'Kevin2026', 'Content-Length': Buffer.byteLength(msgBody) }
};
try {
  await new Promise((r) => {
    const req = http.request(opts, (res) => { res.on('data',()=>{}); res.on('end',r); });
    req.on('error', r);
    req.write(msgBody);
    req.end();
  });
} catch(e) {}

return [{ json: { success: true, to: input.to, subject: input.subject, pipelineId: input.pipelineId, supabaseStatus, logPath, sentAt: input.sentAt } }];
